client_script:
function car_form_fill(user, company, quotation_id, form_name, form_status, form_document) {
    frappe.call({
        method: "alms_app.api.car_process.car_form_fill",
        type: "POST",
        args: { 
            user: user,
            company: company,
            quotation_id: quotation_id,
            form_name: form_name,
            form_status: form_status,
            form_document: form_document,  // Ensure it’s never undefined
        },
        callback: function (response) {
            if (response.message && response.message.status === "success") {
                frappe.msgprint({
                    title: "Success",
                    indicator: "green",
                    message: response.message.message,
                });

                // Reset form or redirect
                frappe.web_form.success && frappe.web_form.success(response.message);
            } else {
                frappe.msgprint({
                    title: "Error",
                    indicator: "red",
                    message: response.message.message || "An unknown error occurred.",
                });
            }
        },
        error: function () {
            frappe.msgprint({
                title: "Error",
                indicator: "red",
                message: "Failed to submit the form. Please try again.",
            });
        },
    });
}

frappe.web_form.validate = () => {
    let user = frappe.web_form.get_value("user");
    let company = frappe.web_form.get_value("company");
    let quotation_id = frappe.web_form.get_value("quotation_form");
    let form_name = "Purchase Form";
    let form_status = frappe.web_form.get_value("po");
    let links = document.getElementsByClassName("attached-file-link");

    let form_document = "";

    if (links.length > 0) {
        form_document = links[0].getAttribute("href");
        //alert("File URL: " + form_document);
        car_form_fill(user, company, quotation_id, form_name, form_status, form_document);
    } else {
        alert("No attached file found!");
    }
};


frappe.web_form.on('quotation_form', (field, value) => {
    frappe.web_form.set_df_property('quotation_form', 'read_only', 1);
});
frappe.web_form.on('user', (field, value) => {
    frappe.web_form.set_df_property('user', 'hidden', 1);
});
frappe.web_form.on('company', (field, value) => {
    frappe.web_form.set_df_property('company', 'hidden', 1);
});
